import React from "react";
import { Card, Container, Form, ListGroup } from "react-bootstrap";
import { useNavigate, useParams } from "react-router";

// widgets
import { VerticalSpacer } from "../sub-components/vertical-spacer";
import { Divider } from "../sub-components/divider";
// icons
// import { AiFillEdit } from "react-icons/ai";
import { FiEdit } from "react-icons/fi";
import { TbLocationFilled } from "react-icons/tb";

// context
import { UPDATE_JOB_CONTEXT } from "../utils/contexts";

// utils
import api from "../utils/api";
import { IS_LOGGED_IN } from "../utils/loggedin";
import { NOTIFICATION_TYPE, SHUTTLE_SERVICE } from "../utils/strings";
import { ROUTE_LINKS } from "../utils/strings";
import { NOTIFICATIONS } from "../utils/notifications";
import { EDIT_VEHICLE_SIZE_MODAL } from "../modals/edit-vehicle-size-modal";
import { EDIT_ROUTES_MODAL } from "../modals/edit-routes-modal";
import { EDIT_ADDITIONAL_INFO_MODAL } from "../modals/edit-additional-info-modal";
import { ErrorHandling } from "../utils/error-handling";
import { AwaitCallBack } from "../utils/await-callback";

// import
import { motion } from "framer-motion";
import { PAGES_VARIANT } from "../utils/animation-variants";
import {
  SECTION_ANIMATION_DELAY,
  SECTION_ANIMATION_DURATION,
} from "../utils/numerics";
import { AnimatedButton } from "../sub-components/animated-button";

// export
export default function UpdateJob() {
  // get url
  const { id } = useParams();
  // navigate
  const navigate = useNavigate();

  //  formaters
  const formater = Intl.NumberFormat("en-ZA", {
    style: "currency",
    currency: "zar",
    minimumSignificantDigits: 1,
  });

  const timeFormater = Intl.DateTimeFormat("en-Za", {
    hour: "numeric",
    minute: "numeric",
    // second: "none",
    timeZone: "Africa/Harare",
    timeZoneName: "short",
  });

  const dateFormater = Intl.DateTimeFormat("en-ZA", {
    weekdays: "long",
    year: "numeric",
    month: "long",
    day: "numeric",
  });

  // react
  const [showAdditionalInfoSection, setShowAdditionalInfoSection] =
    React.useState(false);
  const [showRouteSection, setShowRouteSection] = React.useState(false);
  const [showVehicleSizeSection, setShowVehicleSizeSection] =
    React.useState(false);

  const [job, setJob] = React.useState({});
  const [jobLoaded, setJobLoaded] = React.useState(false);
  const [notificationType, setNotificationType] = React.useState(
    NOTIFICATION_TYPE.none
  );
  const [leadingText, setLeadingText] = React.useState("");
  const [trailingText, setTrailingText] = React.useState("");

  // notification function
  const setNotification = (type, leading, trailing) => {
    setNotificationType((_) => type);
    setLeadingText((_) => leading);
    setTrailingText((_) => trailing);
  };

  // function to determin
  const pickupDropOff = (list, current) => {
    if (current <= 0) {
      return "Pickup";
    } else if (current > 0 && current < list.length - 1) {
      return "Pickup|Dropoff";
    }
    //
    return "Dropoff";
  };

  //
  const setHeaderStatus = (job_loaded) => {
    if (job_loaded) {
      if (job_loaded.job_completed) return [true, job_loaded];
      else if (job_loaded.job_canceled) return [true, job_loaded];
      else return [false, job_loaded];
    }
  };
  //

  // pick job text
  const setHeaderTextColor = (loaded) => {
    if (loaded) {
      if (job.job_completed) return "muted";
      else if (job.job_canceled) return "dark";
      else return "white";
    }
  };
  const setHeaderText = (loaded) => {
    if (loaded) {
      if (job.job_completed) return "COMPLETED";
      else if (job.job_canceled) return "CANCELLED";
      else return "ACTIVE";
    }
  };
  // pick job color
  const setHeaderColor = (loaded) => {
    if (loaded) {
      if (job.job_completed) return "secondary";
      else if (job.job_canceled) return "danger";
      else return "success";
    }
  };
  // section vehicle size
  const jobSection = (leading, onClick, job_details) => {
    // resolve them to their respective components
    const [disable, _job] = job_details;
    // headerClass
    const headerClassName =
      "px-3 py-2 d-flex flex-row justify-content-between align-items-center bg-opacity-75";
    // return
    return (
      <div>
        <AnimatedButton
          onClick={disable ? null : () => onClick(true)}
          className="w-100 mb-3"
        >
          <div className={`bg-${setHeaderColor(_job)} ${headerClassName}`}>
            {/*header*/}
            <span
              className={`text-${setHeaderTextColor(_job)}`}
              style={{ fontWeight: 900, fontSize: `${18 / 16}rem` }}
            >
              {leading}
            </span>
            {/*header*/}
            {/*Icon*/}
            <FiEdit className={`text-${setHeaderTextColor(_job)}`} />
            {/*Icon*/}
          </div>
        </AnimatedButton>
      </div>
    );
  };

  const driverNote = (leading, trailing) => {
    return (
      <div className="px-3 d-flex flex-column justify-content-start align-items-start">
        <span
          className="fw-bold"
          style={{
            color: "#9e9e9e",
          }}
        >
          {leading}
        </span>
        <span className="fw-normal text-dark">{trailing}</span>
      </div>
    );
  };

  //
  const displayItem = (
    leading,
    trailing,
    isDiscount = false,
    isAmountDue = false
  ) => {
    return (
      <div className="px-3 d-flex flex-row justify-content-between align-items-center gap-1">
        <span
          style={{
            color: `${isAmountDue ? "black" : "#9e9e9e"}`,
            fontWeight: `${isAmountDue ? 900 : 800}`,
          }}
        >
          {leading}
        </span>
        <span
          style={{
            color: `${isDiscount ? "red" : "black"}`,
            fontWeight: `${isAmountDue ? "900" : "normal"}`,
            fontSize: isAmountDue ? `${18 / 16}rem` : "",
          }}
        >
          {trailing}
        </span>
      </div>
    );
  };

  // display routes
  const displayRoutes = (routes) => {
    return (
      <Form.Group>
        <ListGroup className="rounded-0 gap-1">
          {routes.map((route, i) => {
            return (
              <ListGroup.Item
                key={i}
                className="p-2 d-flex flex-row justify-content-between align-items-start gap-2 border-white"
                style={{
                  backgroundColor: "var(--primary-color-opacity)",
                }}
              >
                <div className="p-0 m-0 d-flex flex-row justify-content-start align-items-start gap-2">
                  <div>
                    <TbLocationFilled color="red" size={15} />
                  </div>
                  <div className="d-flex flex-column justify-content-start align-items-start">
                    <span
                      className="fw-bolder"
                      style={{ fontSize: "0.875rem", color: "grey" }}
                    >
                      {pickupDropOff(route, i)}
                    </span>
                    <span>{route.route_name}</span>
                  </div>
                </div>
              </ListGroup.Item>
            );
          })}
        </ListGroup>
      </Form.Group>
    );
  };

  // cannot edit completed job
  const editCompleted = (job_loaded) => {
    if (job_loaded.job_completed || job_loaded.job_canceled) {
      return (
        <div className="bg-warning bg-opacity-25 p-3 text-center">
          <span className="mb-2 text-dark">
            <span className="text-danger fw-bold">Please note!</span> a
            completed or cancelled job cannot be edited.
          </span>
        </div>
      );
    }
  };

  // displayAdditional information
  const displayAdditionalInfo = (job) => {
    return (
      <React.Fragment>
        {displayItem("Date", `${dateFormater.format(new Date(job.job_date))}`)}
        {displayItem(
          "Time",
          `${timeFormater.format(new Date(`${job.job_date} ${job.job_time} `))}`
        )}
        {displayItem("Helper", job.helpers)}
        {displayItem("Floors", job.floors)}
        {/* {displayItem("Shuttle", SHUTTLE_SERVICE[job.shuttle].description)} */}
        {/*driver note */}
        {displayItem(
          "Payment method",
          `${job.payment_option}`.toUpperCase().charAt(0) +
            `${job.payment_option}`.toLowerCase().slice(1)
        )}
        {driverNote("Driver note", job.driver_note)}
        {/*driver note */}
      </React.Fragment>
    );
  };

  // loadJob
  const loadJob = (isLoaded) => {
    if (isLoaded) {
      return (
        <React.Fragment>
          {/*section vehicle Size*/}
          <div className="mb-3">
            {jobSection(
              "Job vehicle type",
              setShowVehicleSizeSection,
              setHeaderStatus(job)
            )}
            {displayItem("Vehicle size", `${job.vehicle_size} Ton`)}
          </div>
          {/*section vehicle Size*/}
          {/*section Routes */}
          <div className="mb-3">
            {jobSection(
              "Job routes",
              setShowRouteSection,
              setHeaderStatus(job)
            )}
            {displayRoutes(job.routes)}
          </div>
          {/*section Routes */}
          {/*additional information*/}
          <div className="mb-3">
            {jobSection(
              "Job add-info ",
              setShowAdditionalInfoSection,
              setHeaderStatus(job)
            )}
            {displayAdditionalInfo(job)}
          </div>
          {/*additional information*/}
          {/*Quote*/}

          {displayPrices(job)}
          {/*Quote*/}
        </React.Fragment>
      );
    }

    return <></>;
  };

  // disply prices
  const displayPrices = (job) => {
    return (
      <React.Fragment>
        <Divider width={"100%"} />
        {displayItem("Base fee", `${formater.format(job.base_fee)}`)}
        {displayItem(
          "Off peak",
          `${job.mid_discount > 0 ? "-" : ""} ${formater.format(
            job.mid_discount
          )}`,
          true
        )}
        {displayItem(
          "Return customer",
          `${job.return_customer_discount > 0 ? "-" : ""} ${formater.format(
            job.return_customer_discount
          )}`,
          true
        )}
        <Divider />
        {displayItem(
          "Amount due",
          `${formater.format(job.amount_due)}`,
          false,
          true
        )}
        <Divider />
      </React.Fragment>
    );
  };

  // function to getch
  const fetchUpdateJob = React.useCallback(async () => {
    // check if logged in
    const [verify, _] = IS_LOGGED_IN();
    // verify
    if (verify) {
      //
      setJobLoaded((_) => false);
      setNotification(NOTIFICATION_TYPE.loading, "Fetching Job...", "");

      //
      const url = `jobs/api/get/${id}/`;
      await api
        .get(url)
        .then((r) => {
          // check
          if (r.status === 200) {
            setJob((_) => r.data);
            setJobLoaded((_) => true);
            setNotification(NOTIFICATION_TYPE.none, "", "");
          }
        })
        .catch((e) => {
          // set
          setJobLoaded((_) => false);
          ErrorHandling(e, setNotification);
        });

      return;
    }

    // otherwise
    const message =
      "To view this section you must be signed in. we'll navigate you to the sign-in page.";
    setNotification(NOTIFICATION_TYPE.info, "Dear valued customer. ", message);
    // sleep
    await AwaitCallBack(() => navigate(ROUTE_LINKS.signin), 6000);
    // return
  }, []);

  // load modals
  const loadModals = (loaded, verifiedJob) => {
    if (loaded) {
      return (
        <React.Fragment>
          {/*Additional Info*/}
          <UPDATE_JOB_CONTEXT.Provider
            value={{
              show: showAdditionalInfoSection,
              setShow: setShowAdditionalInfoSection,
              job: verifiedJob,
            }}
          >
            <EDIT_ADDITIONAL_INFO_MODAL />
          </UPDATE_JOB_CONTEXT.Provider>
          {/*Additional Info*/}
          {/*Vehicle size*/}
          <UPDATE_JOB_CONTEXT.Provider
            value={{
              show: showVehicleSizeSection,
              setShow: setShowVehicleSizeSection,
              job: verifiedJob,
            }}
          >
            <EDIT_VEHICLE_SIZE_MODAL />
          </UPDATE_JOB_CONTEXT.Provider>
          {/*Vehicle size*/}
          {/*edit routes*/}
          <UPDATE_JOB_CONTEXT.Provider
            value={{
              show: showRouteSection,
              setShow: setShowRouteSection,
              job: verifiedJob,
            }}
          >
            <EDIT_ROUTES_MODAL />
          </UPDATE_JOB_CONTEXT.Provider>
          {/*edit routes*/}
        </React.Fragment>
      );
    }
  };

  // React hook
  React.useEffect(() => {
    window.scrollTo(0, 0);
    fetchUpdateJob();
  }, [fetchUpdateJob]);

  //safe
  return (
    <motion.section
      className="pb-3 px-3"
      variants={PAGES_VARIANT}
      animate="visible"
      initial="hidden"
      exit="exit"
      transition={{
        duration: SECTION_ANIMATION_DURATION,
        delay: SECTION_ANIMATION_DELAY,
      }}
    >
      <Container className="p-0 d-flex flex-column justify-content-center align-items-center">
        <Card
          className="card__section border-0 rounded-0"
          style={{
            boxShadow: "0 0 4px 0 rgba(95, 95, 95, 0.1)",
            WebkitBoxShadow: "0 0 4px 0 rgba(95, 95, 95, 0.1)",
          }}
        >
          <Card.Header
            className={`bg-${setHeaderColor(
              jobLoaded
            )} text-white rounded-0 border-0 mb-0`}
          >
            <div className="d-flex flex-row justify-content-between align-items-center">
              <span style={{ fontWeight: "900" }}>INVOICE {id}</span>
              <span className={`text-${setHeaderTextColor(jobLoaded)} fw-bold`}>
                {setHeaderText(jobLoaded)}
              </span>
            </div>
          </Card.Header>

          <Card.Body className="p-0">
            {editCompleted(job)}
            {/*NOTIFICATIONS*/}
            {NOTIFICATIONS(notificationType, leadingText, trailingText)}
            {/*NOTIFICATIONS*/}
            {/*Load Job*/}
            {loadJob(jobLoaded)}
            {/*Load Job*/}
          </Card.Body>
        </Card>
        {/*Modals*/}
        {loadModals(jobLoaded, job)}
        {/*Modals*/}
      </Container>
      <VerticalSpacer height={"100px"} />
    </motion.section>
  );
}
